import "core-js/modules/es.json.stringify.js";
export default {
  async getAll() {
    const {
      data,
      error
    } = await fetch('/api/product_rental_availability').then(res => res.json()).catch(err => console.error(err));
    if (error) throw error;
    return data || [];
  },
  async getByProductId(productId) {
    const {
      data,
      error
    } = await fetch(`/api/product_rental_availability/${productId}`).then(res => res.json()).catch(err => console.error(err));
    if (error) throw error;
    return data;
  },
  async create(productData) {
    const {
      data,
      error
    } = await fetch('/api/product_rental_availability', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(productData)
    }).then(res => res.json()).catch(err => console.error(err));
    if (error) throw error;
    return data;
  },
  async update(id, updates) {
    const {
      data,
      error
    } = await fetch(`/api/product_rental_availability/${id}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(updates)
    }).then(res => res.json()).catch(err => console.error(err));
    if (error) throw error;
    return data;
  },
  async delete(id) {
    const {
      error
    } = await fetch(`/api/product_rental_availability/${id}`, {
      method: 'DELETE'
    }).then(res => res.json()).catch(err => console.error(err));
    if (error) throw error;
  }
};
